struct Draw3DImmersiveSpace: ImmersiveSpace {
    @State private var points: [SIMD3<Float>] = []
    var body: some ImmersiveSpaceContent {
        RealityView { content in
            let anchor = AnchorEntity(world: .zero)
            // For each point, add a small sphere or line segment
            for point in points {
                let dot = ModelEntity(mesh: .generateSphere(radius: 0.01))
                dot.position = point
                anchor.addChild(dot)
            }
            content.add(anchor)
        } update: { content in
            // Update points as user draws
        }
        .gesture(SpatialDragGesture().onChanged { value in
            points.append(value.location3D)
        })
    }
}

